function validate(args, output) {
    const expression = args[0];
    if (typeof output !== 'string') return false;
    if ((output.match(/\(/g) || []).length !== 1) return false;
    if ((output.match(/\)/g) || []).length !== 1) return false;
    const idxOpen = output.indexOf('(');
    const idxClose = output.indexOf(')');
    const idxPlus = output.indexOf('+');
    if (idxPlus === -1 || !(idxOpen < idxPlus && idxPlus < idxClose)) return false;
    if (idxPlus - idxOpen - 1 < 1 || idxClose - idxPlus - 1 < 1) return false;
    const stripped = output.slice(0, idxOpen) + output.slice(idxOpen + 1, idxClose) + output.slice(idxClose + 1);
    if (stripped !== expression) return false;
    const prefix = output.slice(0, idxOpen);
    const insideLeft = output.slice(idxOpen + 1, idxPlus);
    const insideRight = output.slice(idxPlus + 1, idxClose);
    const suffix = output.slice(idxClose + 1);
    const leftMult = prefix ? Number(prefix) : 1;
    const rightMult = suffix ? Number(suffix) : 1;
    const value = leftMult * (Number(insideLeft) + Number(insideRight)) * rightMult;
    const plusAt = expression.indexOf('+');
    const num1 = expression.slice(0, plusAt);
    const num2 = expression.slice(plusAt + 1);
    let best = null;
    for (let i = 0; i < num1.length; i++) {
        const p = num1.slice(0, i);
        const il = num1.slice(i);
        for (let j = 1; j <= num2.length; j++) {
            const ir = num2.slice(0, j);
            const s = num2.slice(j);
            const lm = p ? Number(p) : 1;
            const rm = s ? Number(s) : 1;
            const v = lm * (Number(il) + Number(ir)) * rm;
            if (best === null || v < best) best = v;
        }
    }
    return value === best;
}

